            }
        }

        // Continue with remaining elements
        int early_break = 0;
        for (int idx = pos; idx < m; idx++) {
            int ti = partial_seq[idx];
            int so = offsets[ti] * 4;
            int nops = num_ops_arr[ti];
            int ts2 = 1;
            int tl2 = ops_flat[so + 3];

            for (int j = 0; j < nops; j++) {
